 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import {
 4	  DescriptionList,
 5	  DescriptionListGroup,
 6	  DescriptionListTerm,
 7	  DescriptionListDescription,
 8	  Flex,
 9	  Label,
10	} from '@patternfly/react-core';
11	import {
12	  ExclamationTriangleIcon,
13	  ExclamationCircleIcon,
14	} from '@patternfly/react-icons';
15	import { t_global_color_status_danger_default as dangerColor } from '@patternfly/react-tokens';
16	import { t_global_color_status_warning_default as warningColor } from '@patternfly/react-tokens';
17	import { PoolType } from '../../../constants';
18	import { StoragePoolTableData } from './types';
19	
20	export type PoolUtilizationPopoverContentProps = {
21	  pool: StoragePoolTableData;
22	};
23	
24	export const PoolUtilizationPopoverContent: React.FC<
25	  PoolUtilizationPopoverContentProps
26	> = ({ pool }) => {
27	  const { t } = useCustomTranslation();
28	  const Icon = pool.critical ? ExclamationCircleIcon : ExclamationTriangleIcon;
29	  const iconColor = pool.critical ? dangerColor.value : warningColor.value;
30	  const volumeType =
31	    pool.type === PoolType.BLOCK ? t('Block') : t('Filesystem');
32	
33	  return (
34	    <div>
35	      <Flex
36	        alignItems={{ default: 'alignItemsCenter' }}
37	        spaceItems={{ default: 'spaceItemsSm' }}
38	        className="pf-v6-u-mb-sm"
39	      >
40	        <Icon style={{ color: iconColor }} />
41	        <span className="pf-v6-u-font-weight-bold">{pool.metadata.name}</span>
42	      </Flex>
43	      <DescriptionList isHorizontal>
44	        <DescriptionListGroup>
45	          <DescriptionListTerm>{t('Used:')}</DescriptionListTerm>
46	          <DescriptionListDescription>
47	            {pool.usedCapacity}
48	            <Label
49	              variant="filled"
50	              color={pool.type === PoolType.BLOCK ? 'blue' : 'green'}
51	              className="pf-v6-u-ml-sm"
52	            >
53	              {volumeType}
54	            </Label>
55	          </DescriptionListDescription>
56	        </DescriptionListGroup>
57	        <DescriptionListGroup>
58	          <DescriptionListTerm>{t('Maximum available:')}</DescriptionListTerm>
59	          <DescriptionListDescription>
60	            {pool.totalCapacity}
61	          </DescriptionListDescription>
62	        </DescriptionListGroup>
63	      </DescriptionList>
64	      {pool.critical && (
65	        <div className="pf-v6-u-mt-sm pf-v5-u-color-200">
66	          {t('Storage pool critically full. Add capacity to avoid disruptions')}
67	        </div>
68	      )}
69	    </div>
70	  );
71	};

